args.CodeContent:
'use client';

import { useState } from 'react';

interface WikiCategory {
  id: string;
  name: string;
  icon: string;
  articles: WikiArticle[];
}

interface WikiArticle {
  id: string;
  title: string;
  summary: string;
  content: string;
  lastUpdated: string;
}

const WIKI_DATA: WikiCategory[] = [
  {
    id: 'classes',
    name: 'Classes',
    icon: '⚔️',
    articles: [
      {
        id: 'blademaster',
        title: 'Blademaster Guide',
        summary: 'Master of melee combat with devastating sword techniques.',
        content: `The Blademaster is a high-damage melee class specializing in close-range combat. With exceptional mobility and burst damage, Blademasters excel at eliminating priority targets quickly.

**Core Mechanics:**
- Combo System: Chain skills for increased damage
- Blade Mastery: Passive critical strike chance
- Evasion: High dodge rate against physical attacks

**Recommended Build:**
- Primary Stat: Strength (70%), Dexterity (30%)
- Skills: Whirlwind Strike, Blade Dance, Execution
- Equipment: Focus on critical strike and attack speed

**PvP Strategy:**
Close the gap quickly using mobility skills, then unleash high-damage combos. Use evasion to avoid counterattacks and finish with execution abilities.`,
        lastUpdated: '2024-12-10',
      },
      {
        id: 'wizard',
        title: 'Wizard Guide',
        summary: 'Powerful ranged caster with devastating area damage.',
        content: `Wizards harness elemental magic to deal massive area damage from a safe distance. They excel in PvE content and large-scale PvP battles.

**Core Mechanics:**
- Elemental Mastery: Bonus damage to specific elements
- Mana Management: Balance damage output with resource consumption
- Crowd Control: Freeze, stun, and slow enemies

**Recommended Build:**
- Primary Stat: Intelligence (80%), Wisdom (20%)
- Skills: Fireball, Frost Nova, Meteor Storm
- Equipment: Maximize spell power and mana regeneration

**PvE Strategy:**
Position yourself at maximum range and rotate AoE spells. Use crowd control to manage multiple enemies and save burst damage for elite targets.`,
        lastUpdated: '2024-12-08',
      },
    ],
  },
  {
    id: 'dungeons',
    name: 'Dungeons',
    icon: '🏰',
    articles: [
      {
        id: 'dragon-peak',
        title: 'Dragon Peak Dungeon',
        summary: 'Level 50+ dungeon with dragon boss encounters.',
        content: `Dragon Peak is a high-level dungeon requiring a coordinated 5-player party. The dungeon features three boss encounters and numerous trash mob packs.

**Requirements:**
- Level: 50+
- Party Size: 5 players
- Recommended Composition: 1 Tank, 1 Healer, 3 DPS
- Estimated Time: 45-60 minutes

**Boss Mechanics:**

**Boss 1: Flame Guardian**
- Frontal cone fire breath (tank face away from party)
- Summons fire elementals every 30 seconds
- Enrage at 5 minutes

**Boss 2: Ice Wyvern**
- Freezing aura (stay spread out)
- Ice spike ground AoE (dodge blue circles)
- Flight phase at 50% HP

**Boss 3: Ancient Dragon**
- Tail swipe (melee stay at sides)
- Dragon breath (entire party stack behind pillars)
- Add phase at 70%, 40%, 10% HP

**Loot:**
- Epic gear (ilvl 55-60)
- Dragon Scales (crafting material)
- Rare mount drop (0.5% chance)`,
        lastUpdated: '2024-12-12',
      },
    ],
  },
  {
    id: 'crafting',
    name: 'Crafting',
    icon: '🔨',
    articles: [
      {
        id: 'blacksmithing',
        title: 'Blacksmithing Guide',
        summary: 'Craft weapons and armor with blacksmithing profession.',
        content: `Blacksmithing allows you to craft powerful weapons and heavy armor. This profession is essential for endgame gear progression.

**Leveling Path:**
- Level 1-50: Craft basic iron equipment
- Level 51-100: Steel equipment and refinement
- Level 101-150: Mithril equipment and enchantments
- Level 151-200: Legendary crafting

**Key Materials:**
- Iron Ore (Level 1-50)
- Steel Ingots (Level 51-100)
- Mithril Bars (Level 101-150)
- Dragon Scales (Level 151-200)

**Profitable Recipes:**
- +10 Enhancement Stones (always in demand)
- Epic Weapons (high profit margin)
- Legendary Armor Sets (endgame content)

**Tips:**
- Join a guild for material sharing
- Farm dungeons for rare materials
- Check marketplace prices before crafting`,
        lastUpdated: '2024-12-05',
      },
    ],
  },
  {
    id: 'pvp',
    name: 'PvP',
    icon: '⚡',
    articles: [
      {
        id: 'arena-guide',
        title: 'Arena Combat Guide',
        summary: 'Master 1v1 and team arena battles.',
        content: `Arena combat is the ultimate test of skill in Perfect World. Success requires mastery of your class, game knowledge, and strategic thinking.

**Arena Types:**
- 1v1 Duel: Solo combat, best of 3 rounds
- 2v2 Team: Coordinated duo battles
- 3v3 Team: Full team composition battles

**General Strategy:**
1. Know your opponent's class strengths/weaknesses
2. Manage cooldowns and resources efficiently
3. Use terrain and line of sight to your advantage
4. Save defensive cooldowns for burst damage
5. Coordinate crowd control with teammates

**Class Matchups:**
- Blademaster vs Wizard: Close gap quickly, interrupt casts
- Wizard vs Cleric: Burst damage before healing
- Tank vs DPS: Outlast with defensive cooldowns

**Rewards:**
- Arena Points (exchange for gear)
- Titles and achievements
- Seasonal rankings and exclusive rewards`,
        lastUpdated: '2024-12-15',
      },
    ],
  },
  {
    id: 'economy',
    name: 'Economy',
    icon: '💰',
    articles: [
      {
        id: 'gold-making',
        title: 'Gold Making Guide',
        summary: 'Efficient methods to earn gold in Perfect World.',
        content: `Gold is the primary currency in Perfect World. Here are the most efficient methods to accumulate wealth.

**Daily Activities (30-60 min):**
- Daily Quests: 50,000-100,000 gold
- Dungeon Runs: 75,000-150,000 gold + loot
- Gathering: 25,000-50,000 gold (herbs, ore)

**Weekly Activities:**
- Territory War: 200,000-500,000 gold (if victorious)
- Raid Bosses: 100,000-300,000 gold + rare drops
- Weekly Quests: 150,000-250,000 gold

**Marketplace Trading:**
- Buy low, sell high (requires market knowledge)
- Flip rare materials during events
- Craft and sell popular consumables
- Auction rare drops from dungeons

**Long-term Investments:**
- Rare mounts (appreciate over time)
- Limited edition cosmetics
- Legendary crafting materials

**Tips:**
- Track marketplace trends
- Join an active guild for group farming
- Invest in bag space for efficient farming
- Save gold for major updates (new gear releases)`,
        lastUpdated: '2024-12-01',
      },
    ],
  },
  {
    id: 'events',
    name: 'Events',
    icon: '🎉',
    articles: [
      {
        id: 'seasonal-events',
        title: 'Seasonal Events Calendar',
        summary: 'Annual events and limited-time activities.',
        content: `Perfect World features numerous seasonal events throughout the year, each offering exclusive rewards.

**Annual Events:**

**Winter Solstice (December)**
- Duration: 3 weeks
- Activities: Snowball fights, ice dungeon, gift exchange
- Rewards: Frost Mount, Ice Crown, Snow Cloak

**Spring Festival (March)**
- Duration: 2 weeks
- Activities: Flower gathering, spring boss raids
- Rewards: Cherry Blossom Pet, Spring Fashion Set

**Summer Celebration (July)**
- Duration: 4 weeks
- Activities: Beach events, water combat, fishing tournament
- Rewards: Surfboard Mount, Summer Swimwear

**Autumn Harvest (October)**
- Duration: 2 weeks
- Activities: Farming competition, cooking contest
- Rewards: Harvest Pet, Autumn Cloak

**Special Events:**
- Double EXP Weekends (monthly)
- Territory War Tournaments (quarterly)
- World Boss Invasions (random)

**Event Tips:**
- Check event calendar weekly
- Complete daily event quests for maximum rewards
- Save event currency for exclusive items
- Participate in guild events for bonus rewards`,
        lastUpdated: '2024-11-28',
      },
    ],
  },
];

export default function WikiPage() {
  const [activeCategory, setActiveCategory] = useState<string>('classes');
  const [selectedArticle, setSelectedArticle] = useState<WikiArticle | null>(
    WIKI_DATA[0].articles[0]
  );
  const [searchQuery, setSearchQuery] = useState('');

  const currentCategory = WIKI_DATA.find((cat) => cat.id === activeCategory);

  const filteredArticles = currentCategory?.articles.filter((article) =>
    article.title.toLowerCase().includes(searchQuery.toLowerCase())
  );

  return (
    <main style={{ background: '#0a0a0f', minHeight: '100vh', padding: '3rem 1rem' }}>
      <div style={{ maxWidth: '1600px', margin: '0 auto' }}>
        {/* Header */}
        <div style={{ marginBottom: '2.5rem' }}>
          <h1
            style={{
              color: '#ffffff',
              fontSize: 'clamp(2rem, 5vw, 3.5rem)',
              fontWeight: 900,
              textTransform: 'uppercase',
              letterSpacing: '-0.02em',
            }}
          >
            WIKI
          </h1>
          <p style={{ marginTop: '0.5rem', color: '#8b8ba3', fontSize: '1rem' }}>
            Game guides, class information, and community knowledge base.
          </p>
        </div>

        {/* Search Bar */}
        <div style={{ marginBottom: '2rem' }}>
          <input
            type="text"
            placeholder="Search articles..."
            value={searchQuery}
            onChange={(e) => setSearchQuery(e.target.value)}
            style={{
              width: '100%',
              maxWidth: '600px',
              padding: '0.875rem 1.25rem',
              background: '#12121a',
              border: '2px solid #2a2a3a',
              color: '#ffffff',
              fontSize: '1rem',
              outline: 'none',
              transition: 'border-color 0.2s, box-shadow 0.2s',
            }}
            onFocus={(e) => {
              e.currentTarget.style.borderColor = '#00e5ff';
              e.currentTarget.style.boxShadow = '0 0 12px #00e5ff44';
            }}
            onBlur={(e) => {
              e.currentTarget.style.borderColor = '#2a2a3a';
              e.currentTarget.style.boxShadow = 'none';
            }}
          />
        </div>

        <div style={{ display: 'grid', gridTemplateColumns: '250px 1fr', gap: '2rem' }}>
          {/* Sidebar Categories */}
          <aside>
            <nav style={{ position: 'sticky', top: '2rem' }}>
              <h2
                style={{
                  fontSize: '0.875rem',
                  fontWeight: 700,
                  textTransform: 'uppercase',
                  color: '#8b8ba3',
                  marginBottom: '1rem',
                  letterSpacing: '0.05em',
                }}
              >
                Categories
              </h2>
              <div style={{ display: 'flex', flexDirection: 'column', gap: '0.5rem' }}>
                {WIKI_DATA.map((category) => (
                  <button
                    key={category.id}
                    onClick={() => {
                      setActiveCategory(category.id);
                      setSelectedArticle(category.articles[0]);
                      setSearchQuery('');
                    }}
                    style={{
                      padding: '0.75rem 1rem',
                      display: 'flex',
                      alignItems: 'center',
                      gap: '0.75rem',
                      background: activeCategory === category.id ? '#00e5ff' : '#12121a',
                      color: activeCategory === category.id ? '#0a0a0f' : '#ffffff',
                      border: '2px solid',
                      borderColor: activeCategory === category.id ? '#00e5ff' : '#2a2a3a',
                      textAlign: 'left',
                      cursor: 'pointer',
                      transition: 'all 0.2s',
                      fontWeight: activeCategory === category.id ? 700 : 400,
                      boxShadow:
                        activeCategory === category.id ? '0 0 12px #00e5ff44' : 'none',
                    }}
                    onMouseEnter={(e) => {
                      if (activeCategory !== category.id) {
                        e.currentTarget.style.background = '#1a1a2a';
                        e.currentTarget.style.borderColor = '#00e5ff';
                      }
                    }}
                    onMouseLeave={(e) => {
                      if (activeCategory !== category.id) {
                        e.currentTarget.style.background = '#12121a';
                        e.currentTarget.style.borderColor = '#2a2a3a';
                      }
                    }}
                  >
                    <span style={{ fontSize: '1.25rem' }}>{category.icon}</span>
                    <span style={{ fontSize: '1rem' }}>{category.name}</span>
                  </button>
                ))}
              </div>
            </nav>
          </aside>

          {/* Main Content */}
          <div style={{ display: 'grid', gridTemplateColumns: '300px 1fr', gap: '2rem' }}>
            {/* Article List */}
            <div>
              <h2
                style={{
                  fontSize: '1.25rem',
                  fontWeight: 700,
                  textTransform: 'uppercase',
                  color: '#ffffff',
                  marginBottom: '1rem',
                }}
              >
                {currentCategory?.name}
              </h2>
              <div style={{ display: 'flex', flexDirection: 'column', gap: '0.75rem' }}>
                {filteredArticles && filteredArticles.length > 0 ? (
                  filteredArticles.map((article) => (
                    <button
                      key={article.id}
                      onClick={() => setSelectedArticle(article)}
                      style={{
                        padding: '1rem',
                        background:
                          selectedArticle?.id === article.id ? '#1a1a2a' : '#12121a',
                        border: '2px solid',
                        borderColor:
                          selectedArticle?.id === article.id ? '#00e5ff' : '#2a2a3a',
                        textAlign: 'left',
                        cursor: 'pointer',
                        transition: 'all 0.2s',
                        boxShadow:
                          selectedArticle?.id === article.id
                            ? '0 0 12px #00e5ff22'
                            : 'none',
                      }}
                      onMouseEnter={(e) => {
                        if (selectedArticle?.id !== article.id) {
                          e.currentTarget.style.borderColor = '#00e5ff';
                        }
                      }}
                      onMouseLeave={(e) => {
                        if (selectedArticle?.id !== article.id) {
                          e.currentTarget.style.borderColor = '#2a2a3a';
                        }
                      }}
                    >
                      <h3
                        style={{
                          fontSize: '1rem',
                          fontWeight: 700,
                          color: '#ffffff',
                          marginBottom: '0.25rem',
                        }}
                      >
                        {article.title}
                      </h3>
                      <p
                        style={{
                          fontSize: '0.875rem',
                          color: '#8b8ba3',
                          lineHeight: 1.4,
                        }}
                      >
                        {article.summary}
                      </p>
                    </button>
                  ))
                ) : (
                  <div
                    style={{
                      padding: '2rem',
                      background: '#12121a',
                      border: '2px solid #2a2a3a',
                      textAlign: 'center',
                    }}
                  >
                    <p style={{ color: '#8b8ba3' }}>No articles found</p>
                  </div>
                )}
              </div>
            </div>

            {/* Article Content */}
            <div>
              {selectedArticle ? (
                <article
                  style={{
                    background: '#12121a',
                    border: '2px solid #2a2a3a',
                    padding: '2rem',
                  }}
                >
                  <header style={{ marginBottom: '1.5rem' }}>
                    <h1
                      style={{
                        fontSize: '2rem',
                        fontWeight: 700,
                        textTransform: 'uppercase',
                        color: '#ffffff',
                        marginBottom: '0.5rem',
                      }}
                    >
                      {selectedArticle.title}
                    </h1>
                    <p style={{ fontSize: '0.875rem', color: '#8b8ba3' }}>
                      Last updated: {new Date(selectedArticle.lastUpdated).toLocaleDateString('en-US', { year: 'numeric', month: 'long', day: 'numeric' })}
                    </p>
                  </header>
                  <div
                    style={{
                      fontSize: '1rem',
                      color: '#ffffff',
                      lineHeight: 1.8,
                      whiteSpace: 'pre-line',
                    }}
                  >
                    {selectedArticle.content}
                  </div>
                </article>
              ) : (
                <div
                  style={{
                    background: '#12121a',
                    border: '2px solid #2a2a3a',
                    padding: '3rem',
                    textAlign: 'center',
                  }}
                >
                  <div style={{ fontSize: '3rem', marginBottom: '1rem' }}>📖</div>
                  <p style={{ color: '#8b8ba3', fontSize: '1rem' }}>
                    Select an article to read
                  </p>
                </div>
              )}
            </div>
          </div>
        </div>
      </div>
    </main>
  );
}

